mapper.select:
select ci.id as cartItemId, ci.product_id as productId, ci.batch_id as batchId, ci.name, ci.image, ci.product_spec as productSpec, ci.number as quantity, ci.amount, case when ib.id is null or ib.status != 1 or ib.expiration_time < now() or p.status != 1 or c.status != 1 or c.type != 1 then 0 else greatest(ib.stock_quantity - ib.locked_quantity - ib.sold_quantity, 0) end as availableQuantity from cart_item ci left join product p on p.id = ci.product_id left join category c on c.id = p.category_id left join inventory_batch ib on ib.id = ci.batch_id where ci.user_id = #{userId} and ci.id in
#{cartItemId}
order by ci.create_time asc, ci.id asc

select ci.id as cartItemId, ci.product_id as productId, ci.batch_id as batchId, ci.name, ci.image, ci.product_spec as productSpec, ci.number as quantity, ci.amount, case when ib.id is null or ib.status != 1 or ib.expiration_time < current_timestamp() or p.status != 1 or c.status != 1 or c.type != 1 then 0 else case when (ib.stock_quantity - ib.locked_quantity - ib.sold_quantity) < 0 then 0 else (ib.stock_quantity - ib.locked_quantity - ib.sold_quantity) end end as availableQuantity from cart_item ci left join product p on p.id = ci.product_id left join category c on c.id = p.category_id left join inventory_batch ib on ib.id = ci.batch_id where ci.user_id = #{userId} and ci.id in
#{cartItemId}
order by ci.create_time asc, ci.id asc

mapper.update:
update inventory_batch
set
    locked_quantity = locked_quantity + #{quantity},
    update_time = #{updateTime}
where id = #{batchId}
  and status = 1
  and expiration_time >= now()
  and (stock_quantity - locked_quantity - sold_quantity) >= #{quantity}

update inventory_batch
set
    locked_quantity = locked_quantity - #{quantity},
    update_time = #{updateTime}
where id = #{batchId}
  and locked_quantity >= #{quantity}

