select o.id, o.number, o.status, o.pay_status as payStatus, o.amount, o.remark, o.pickup_code as pickupCode, o.order_time as orderTime, o.pickup_deadline as pickupDeadline from orders o where o.user_id = #{userId}
and o.status = #{status}
order by ${sortColumn} ${sortOrder}, o.id desc limit #{pageSize} offset #{offset}

select count(1)
from orders o
where o.user_id = #{userId}

    and o.status = #{status}

select od.order_id as orderId, od.product_id as productId, od.batch_id as batchId, od.name, od.image, od.product_spec as productSpec, od.number, od.amount from order_detail od where od.order_id in
#{orderId}
order by od.order_id desc, od.id asc

mapper.update:
update orders
set
    status = #{cancelledStatus},
    cancel_reason = #{cancelReason},
    cancel_time = #{cancelTime}
where id = #{id}
  and status = #{pendingStatus}
  and pay_status = #{unpaidPayStatus}
  and order_time <= #{deadline}
